  8→import SwiftUI
  9→
 10→struct PhaseSectionView: View {
 11→    @Environment(AppRouter.self) private var router
 12→    @Environment(WorkoutSessionStore.self) private var sessionStore
 13→
 14→    let phase: WorkoutPlanPhase
 15→    let phaseIndex: Int
 16→    let displayMode: PhaseDisplayMode
 17→    var isExecuting: Bool = false
 18→    var restTimerStore: RestTimerStore?
 19→    var onSetCompleted: ((Int, ExercisePrescription) -> Void)?
 20→
 21→    @State private var showDeleteConfirmation = false
 22→    @State private var itemToDelete: Int?
 23→
 24→    var body: some View {
 25→        if !filteredItems.isEmpty {
 26→            VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
 27→                SectionHeader(
 28→                    title: phaseHeaderTitle,
 29→                    actionTitle: nil,
 30→                    action: nil
 31→                )
 32→                .padding(.horizontal, -FitTodaySpacing.md)
 33→
 34→                LazyVStack(spacing: FitTodaySpacing.sm) {
 35→                    ForEach(filteredItems.indices, id: \.self) { idx in
 36→                        let item = filteredItems[idx]
 37→                        switch item {
 38→                        case .activity(let activity):
 39→                            ActivityRow(activity: activity)
 40→
 41→                        case .exercise(let prescription):
 42→                            let localIndex = idx + 1
 43→                            let globalIndex = globalExerciseIndex(for: prescription)
 44→
 45→                            if isExecuting, let globalIndex {
 46→                                exerciseExecutionCard(
 47→                                    prescription: prescription,
 48→                                    exerciseIndex: globalIndex,
 49→                                    localIndex: localIndex
 50→                                )
 51→                            } else {
 52→                                Button {
 53→                                    router.push(.workoutExercisePreview(prescription), on: .home)
 54→                                } label: {
 55→                                    WorkoutExerciseRow(
 56→                                        index: localIndex,
 57→                                        prescription: prescription,
 58→                                        isCurrent: sessionStore.currentExerciseIndex == localIndex
 59→                                    )
 60→                                }
 61→                                .buttonStyle(ExerciseRowButtonStyle())
 62→                                .contextMenu {
 63→                                    Button {
 64→                                        router.push(.workoutExercisePreview(prescription), on: .home)
 65→                                    } label: {
 66→                                        Label("Ver detalhes", systemImage: "info.circle")
 67→                                    }
 68→
 69→                                    Button(role: .destructive) {
 70→                                        itemToDelete = idx
 71→                                        showDeleteConfirmation = true
 72→                                    } label: {
 73→                                        Label("Remover exercício", systemImage: "trash")
 74→                                    }
 75→                                }
 76→                                .accessibilityHint("Toque para ver detalhes. Segure para mais opções.")
 77→                            }
 78→                        }
 79→                    }
 80→                }
 81→            }
 82→            .padding(.top, FitTodaySpacing.md)
 83→            .confirmationDialog(
 84→                "Remover exercício?",
 85→                isPresented: $showDeleteConfirmation,
 86→                titleVisibility: .visible
 87→            ) {
 88→                Button("Remover", role: .destructive) {
 89→                    if let idx = itemToDelete {
 90→                        withAnimation(.easeInOut(duration: 0.3)) {
 91→                            sessionStore.removeExercise(fromPhase: phaseIndex, at: idx)
 92→                        }
 93→                    }
 94→                    itemToDelete = nil
 95→                }
 96→                Button("Cancelar", role: .cancel) {
 97→                    itemToDelete = nil
 98→                }
 99→            } message: {
100→                Text("Este exercício será removido do treino atual.")
101→            }
102→        }
103→    }
104→
105→    // MARK: - Execution Card
106→
107→    @ViewBuilder
108→    private func exerciseExecutionCard(prescription: ExercisePrescription, exerciseIndex: Int, localIndex: Int) -> some View {
109→        let progress = sessionStore.progress?.exercises[safe: exerciseIndex]
110→        let isCurrentExercise = sessionStore.currentExerciseIndex == exerciseIndex
111→
112→        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
113→            // Exercise header
114→            HStack(alignment: .top, spacing: FitTodaySpacing.md) {
115→                ExerciseThumbnail(media: prescription.exercise.media, size: 56)
116→
117→                VStack(alignment: .leading, spacing: FitTodaySpacing.xs) {
118→                    Text("\(localIndex). \(prescription.exercise.name)")
119→                        .font(FitTodayFont.ui(size: 16, weight: .bold))
120→                        .foregroundStyle(FitTodayColor.textPrimary)
121→
122→                    HStack(spacing: FitTodaySpacing.sm) {
123→                        Text("\(prescription.sets) " + "execution.sets".localized)
124→                        Text("·").foregroundStyle(FitTodayColor.textTertiary)
125→                        Text("\(prescription.reps.display) reps")
126→                        Text("·").foregroundStyle(FitTodayColor.textTertiary)
127→                        Text("\(Int(prescription.restInterval))s " + "execution.rest".localized)
128→                    }
129→                    .font(FitTodayFont.ui(size: 12, weight: .medium))
130→                    .foregroundStyle(FitTodayColor.textSecondary)
131→                }
132→
133→                Spacer()
134→
135→                if let progress {
136→                    MiniProgressRing(progress: progress.progressPercentage, size: 28)
137→                }
138→            }
139→
140→            // Set tracking rows
141→            if let progress {
142→                // Column headers
143→                HStack(spacing: FitTodaySpacing.sm) {
144→                    Spacer().frame(width: 28)
145→                    Text("execution.set".localized)
146→                        .frame(width: 52, alignment: .leading)
147→                    Spacer()
148→                    Text("Reps")
149→                        .frame(width: 60, alignment: .center)
150→                    Text("execution.weight".localized)
151→                        .frame(width: 68, alignment: .center)
152→                }
153→                .font(FitTodayFont.ui(size: 11, weight: .medium))
154→                .foregroundStyle(FitTodayColor.textTertiary)
155→                .padding(.horizontal, FitTodaySpacing.md)
156→
157→                VStack(spacing: FitTodaySpacing.xs) {
158→                    ForEach(Array(progress.sets.enumerated()), id: \.element.id) { setIdx, setProgress in
159→                        SetCheckbox(
160→                            setNumber: setProgress.setNumber,
161→                            isCompleted: setProgress.isCompleted,
162→                            reps: prescription.reps.display,
163→                            actualReps: setProgress.actualReps,
164→                            weight: setProgress.weight,
165→                            onToggle: {
166→                                sessionStore.toggleSet(exerciseIndex: exerciseIndex, setIndex: setIdx)
167→                                if !setProgress.isCompleted && setIdx < progress.sets.count - 1 {
168→                                    onSetCompleted?(exerciseIndex, prescription)
169→                                }
170→                            },
171→                            onRepsChanged: { reps in
172→                                sessionStore.updateSetReps(exerciseIndex: exerciseIndex, setIndex: setIdx, reps: reps)
173→                            },
174→                            onWeightChanged: { weight in
175→                                sessionStore.updateSetWeight(exerciseIndex: exerciseIndex, setIndex: setIdx, weight: weight)
176→                            }
177→                        )
178→                    }
179→                }
180→
181→                // Inline rest timer
182→                if isCurrentExercise, let restTimerStore, restTimerStore.isActive {
183→                    InlineRestTimerBar(timerStore: restTimerStore)
184→                        .transition(.opacity.combined(with: .scale(scale: 0.95)))
185→                }
186→            }
187→        }
188→        .padding(FitTodaySpacing.md)
189→        .background(
190→            RoundedRectangle(cornerRadius: FitTodayRadius.md)
191→                .fill(isCurrentExercise ? FitTodayColor.surfaceElevated : FitTodayColor.surface)
192→        )
193→        .overlay(
194→            RoundedRectangle(cornerRadius: FitTodayRadius.md)
195→                .stroke(isCurrentExercise ? FitTodayColor.brandPrimary.opacity(0.3) : Color.clear, lineWidth: 1)
196→        )
197→    }
198→
199→    // MARK: - Computed Properties
200→
201→    private var isFilterablePhase: Bool {
202→        phase.kind == .warmup || phase.kind == .aerobic || phase.kind == .finisher
203→    }
204→
205→    private var filteredItems: [WorkoutPlanItem] {
206→        guard isFilterablePhase else {
207→            return phase.items
208→        }
209→
210→        switch displayMode {
211→        case .auto:
212→            return phase.items
213→        case .exercises:
214→            return phase.items.filter { item in
215→                if case .exercise = item { return true }
216→                return false
217→            }
218→        case .guided:
219→            return phase.items.filter { item in
220→                if case .activity = item { return true }
221→                return false
222→            }
223→        }
224→    }
225→
226→    private var phaseHeaderTitle: String {
227→        var title = phase.title
228→
229→        if isFilterablePhase && displayMode != .auto {
230→            let modeIndicator = displayMode == .exercises ? "🏋️" : "🎯"
231→            title = "\(title) \(modeIndicator)"
232→        }
233→
234→        if let rpe = phase.rpeTarget {
235→            return "\(title) · RPE \(rpe)"
236→        }
237→        return title
238→    }
239→
240→    private func globalExerciseIndex(for prescription: ExercisePrescription) -> Int? {
241→        sessionStore.exercises.firstIndex(where: { $0.exercise.id == prescription.exercise.id })
242→    }
243→}
244→
245→// MARK: - Safe Collection Index
246→
247→extension Collection {
248→    subscript(safe index: Index) -> Element? {
249→        indices.contains(index) ? self[index] : nil
250→    }
251→}
252→
253→// MARK: - Button Style for Exercise Row
254→
255→struct ExerciseRowButtonStyle: ButtonStyle {
256→    func makeBody(configuration: Configuration) -> some View {
257→        configuration.label
258→            .opacity(configuration.isPressed ? 0.7 : 1.0)
259→            .scaleEffect(configuration.isPressed ? 0.98 : 1.0)
260→            .animation(.easeInOut(duration: 0.15), value: configuration.isPressed)
261→    }
262→}
